import dspy
import vex

from dspy.teleprompt import BootstrapFewShot

class TriageModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.generate_triage = dspy.ChainOfThought('symptoms: str -> urgency: str')

    def forward(self, symptoms: str):
        return self.generate_triage(symptoms)

@vex.verify({
    'no_hallucination': 'output.urgency in ["emergency", "urgent", "routine", "unknown"]',
    'consistent_reasoning': 'len(output.reasoning.split()) < 100',
    'no_phi_leak': '~output.urgency.contains("patient" or "name")'
})
def verified_triage_module(symptoms: str):
    triage = TriageModule()
    pred = triage(symptoms)
    return pred

# Test with healthcare data
result = verified_triage_module('severe chest pain, shortness of breath')
print(result.urgency)

import dspy
import vex

class HealthcarePipeline(dspy.Module):
    def __init__(self):
        super().__init__()
        self.summarize = dspy.ChainOfThought('notes: str -> summary: str')
        self.diagnose = dspy.ChainOfThought('summary: str -> diagnosis: str')

    def forward(self, notes: str):
        summary = self.summarize(notes)
        diagnosis = self.diagnose(summary)
        return dspy.Prediction(summary=summary.summary, diagnosis=diagnosis.diagnosis)

@vex.verify({
    'pipeline_safety': 'output.diagnosis.confidence > 0.7',
    'no_contraindications': '~output.diagnosis.contains("aspirin" and "bleeding")',
    'audit_trail': 'True',
    'fda_21cfr11': 'output.signature == "verified"'
})
def safe_pipeline(notes: str):
    pipeline = HealthcarePipeline()
    result = pipeline(notes)
    result.signature = "verified"
    return result

clinical_notes = "Patient reports chest pain, recent surgery, no allergies"
output = safe_pipeline(clinical_notes)
print(output.diagnosis)
